#include<bits/stdc++.h>
using namespace std;

const int N = 505;
const int M = 1000005;

int fa[N], v[N];

int find(int x)
{
    return x == fa[x] ? x : fa[x] = find(fa[x]);
}

void merge(int x, int y)
{
    fa[find(x)] = find(y);
}

struct Edge
{
    int u, v, w;
    void read()
    {
        cin >> u >> v >> w;
    }
}e[M + N];

bool cmp(Edge x, Edge y)
{
    return x.w < y.w;
}

int main()
{
    int n, a, ans = 0, cnt = 0;
    cin >> a >> n;
    for(int i = 1; i <= n; i++)
        fa[i] = i;
    for(int i = 1; i <= n; i++)
    	e[++cnt] = {0, i, a};
    for(int i = 1; i <= n; i++)
    	for(int j = 1; j <= n; j++)
    	{
    		int p;
    		cin >> p;
    		if(p > 0 && p < a) e[++cnt] = {i, j, p};
    	}
    sort(e + 1, e + cnt + 1, cmp);
    for(int i = 1; i <= cnt; i++)
    {
        int u = e[i].u, v = e[i].v, w = e[i].w;
        if(find(u) != find(v))
        {
            ans += w;
            merge(u, v);
        }
    }
    cout << ans;
}
